    56→static void test_representative_100(void)
    57→{
    58→    /* --- Section 1: Special IEEE 754 values (7) --- */
    59→    emit(0.0);
    60→    emit(-0.0);
    61→    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    62→    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    63→    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    64→    emit_u(0x7ff0000000000000ULL);  /* +Inf -> +Inf */
    65→    emit_u(0xfff0000000000000ULL);  /* -Inf -> 0 */
    66→
    67→    /* --- Section 2: Subnormal (denormal) values (6) --- */
    68→    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    69→    emit_u(0x8000000000000001ULL);  /* min negative subnormal: -2^-1074 */
    70→    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    71→    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    72→    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    73→    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */
    74→
    75→    /* --- Section 3: Normal boundary values (5) --- */
    76→    emit(DBL_MIN);                  /* 2^-1022, smallest positive normal */
    77→    emit(-DBL_MIN);
    78→    emit_u(0x0010000000000001ULL);  /* one ULP above DBL_MIN */
    79→    emit(DBL_MAX);                  /* 0x7fefffffffffffff, largest finite */
    80→    emit(-DBL_MAX);
    81→
    82→    /* --- Section 4: ULP neighbors of 1.0 (6) --- */
    83→    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0 */
    84→    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0 */
    85→    emit_u(0x3feffffffffffffeULL);  /* two ULPs below 1.0 */
    86→    emit_u(0x3ff0000000000002ULL);  /* two ULPs above 1.0 */
    87→    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0 */
    88→    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0 */
    89→
