    91→    emit_u(0x3fdffffffffffffULL);   /* one ULP below 0.5 */
    92→    emit_u(0x3fe0000000000001ULL);  /* one ULP above 0.5 */
    93→    emit_u(0x3fc0000000000000ULL);  /* 0.25: another exponent boundary */
    94→    emit_u(0x3fffffffffffffffULL);  /* one ULP below 2.0 */
    95→    emit_u(0x4000000000000001ULL);  /* one ULP above 2.0 */
    96→    emit_u(0x4010000000000000ULL);  /* 4.0: next power-of-2 boundary */
    97→
    98→    /* --- Section 6: Exp-specific mathematical constants (16) --- */
    99→    emit(1.0);                      /* exp(1) = e */
   100→    emit(-1.0);                     /* exp(-1) = 1/e */
   101→    emit(0.5);                      /* exp(0.5) = sqrt(e) */
   102→    emit(-0.5);
