   108→    emit_u(0xbfe62e42fefa39efULL);  /* -ln(2): exp = 0.5 */
   109→    emit_u(0x40026bb1bbb55516ULL);  /* ln(10) ~ 2.302585: exp = 10.0 */
   110→    emit_u(0xc0026bb1bbb55516ULL);  /* -ln(10): exp = 0.1 */
   111→    emit_u(0x4005bf0a8b145769ULL);  /* e ~ 2.71828: exp(e) */
   112→    emit(-2.718281828459045);       /* exp(-e) */
   113→    emit(10.0);                     /* exp(10) */
