   127→    emit_u(0x40862e42fefa39efULL);  /* exp overflow threshold ~ 709.782712 */
   128→    emit_u(0x40862e42fefa39eeULL);  /* one ULP below overflow threshold */
   129→    emit_u(0x40862e42fefa39f0ULL);  /* one ULP above overflow threshold -> +Inf */
   130→    emit(709.0);                    /* just below overflow */
   131→    emit(709.5);                    /* near overflow */
   132→    emit(709.78);                   /* near threshold */
   133→    emit_u(0xc0878794eca17ac6ULL);  /* exp underflow threshold ~ -745.1332 */
   134→    emit_u(0xc0878794eca17ac5ULL);  /* one ULP less negative than underflow threshold */
   135→    emit_u(0xc0878794eca17ac7ULL);  /* one ULP more negative -> rounds to 0 */
   136→    emit(-745.0);                   /* near underflow boundary */
   137→    emit(-745.13);                  /* closer to underflow */
   138→    emit(-746.0);                   /* below underflow threshold -> 0 */
   139→
