   168→    emit(-1.0e300);                 /* deep underflow -> 0 */
   169→    emit_u(0x3cb0000000000000ULL);  /* 2^-52: near boundary of exp(x) ~ 1+x */
   170→    emit_u(0xbcb0000000000000ULL);  /* -2^-52 */
   171→    emit_u(0x3c90000000000000ULL);  /* 2^-54: well inside linear region */
   172→    emit_u(0xbc90000000000000ULL);  /* -2^-54 */
