   181→/* Sweep [-100, 100] in 200 steps each */
   182→static void test_sweep(void)
   183→{
   184→    double hi = 100.0;
   185→    int nsteps = 200;
   186→    double step = (2.0 * hi) / (double)nsteps;
   187→
   188→    /* [-100, 0] */
   189→    for (int i = 0; i <= nsteps; i++)
   190→        emit(-hi + (double)i * step);
   191→
   192→    /* [0, 100] */
   193→    for (int i = 0; i <= nsteps; i++)
   194→        emit((double)i * step);
   195→}
   196→
   197→/* Sample [0, 1] at power-of-2 exponent boundaries */
   198→static void test_exhaustive_small(void)
   199→{
   200→    static const uint64_t vals[] = {
   201→        0x0000000000000000ULL, /* 0.0 */
   202→        0x3fc0000000000000ULL, /* 0.125 */
   203→        0x3fd0000000000000ULL, /* 0.25 */
   204→        0x3fd8000000000000ULL, /* 0.375 */
   205→        0x3fe0000000000000ULL, /* 0.5 */
   206→        0x3fe4000000000000ULL, /* 0.625 */
   207→        0x3fe8000000000000ULL, /* 0.75 */
   208→        0x3ff0000000000000ULL, /* 1.0 */
   209→    };
   210→    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
   211→        emit_u(vals[i]);
   212→}
   213→
